def main():
    records = [sft(text, meta) for text, meta in DATA]

    with open(OUTPUT, "a", encoding="utf-8") as f:
        for r in records:
            f.write(json.dumps(r, ensure_ascii=False) + "\n")

    print(f"Дописано {len(records)} SFT-записей → {OUTPUT}")

    # Проверка итогового покрытия
    from collections import Counter
    all_types = Counter()

    with open(str(DATASET_DIR / "training" / "train_clean.jsonl")) as f:
        for line in f:
            r = json.loads(line)
            resp = json.loads(r["messages"][2]["content"])
            all_types[resp["document_type"]] += 1

    with open(str(OUTPUT)) as f:
        for line in f:
            r = json.loads(line)
            resp = json.loads(r["messages"][2]["content"])
            all_types[resp["document_type"]] += 1

    total = sum(all_types.values())
    under_5 = [(t, c) for t, c in all_types.items() if c < 5]

    print(f"\nИТОГО: {total} записей, {len(all_types)} типов")
    print(f"Типов с < 5 примерами: {len(under_5)}")
    if under_5:
        for t, c in sorted(under_5, key=lambda x: x[1]):
            print(f"  {c}  {t}")
    else:
        print("  ВСЕ ТИПЫ >= 5 ПРИМЕРОВ!")


if __name__ == "__main__":
    main()
